<?php
// Migration script — ARISE Platform — 2026-05-11
// Self-deletes after execution. Safe to run multiple times (idempotent).

$dbPath = '/home/cpmsfdav/public_html/arise/data/arise.db';
if (!file_exists($dbPath)) {
    $dbPath = __DIR__ . '/data/arise.db';
}

$results = [];
$errors  = [];

function ok(string $msg): string {
    return '<li style="color:#1a7a1a">&#10003; ' . htmlspecialchars($msg) . '</li>';
}
function fail(string $msg): string {
    return '<li style="color:#a00">&#10007; ' . htmlspecialchars($msg) . '</li>';
}

try {
    if (!file_exists($dbPath)) {
        throw new Exception("Database not found at: $dbPath");
    }

    $db = new SQLite3($dbPath);
    $db->enableExceptions(true);
    $db->exec('PRAGMA journal_mode=WAL;');
    $db->exec('PRAGMA foreign_keys=OFF;');

    // -------------------------------------------------------------------------
    // STEP 1 — Remove old test/empty modules 12–16
    // -------------------------------------------------------------------------
