        VALUES (21, 'Biblical Foundation on Sexuality', 'biblical-sexuality',
        'Exploring what the Bible teaches about sexuality, purity, relationships, and God''s design for human intimacy.',
        'cross', 21, 1);");
    $mod21 = $db->querySingle("SELECT id FROM modules WHERE id=21");
    if ($mod21 == 21) {
        $results[] = ok('Step 2: Module 21 (Biblical Foundation on Sexuality) exists');
    } else {
        $errors[] = fail('Step 2: Module 21 not found after INSERT OR IGNORE');
    }

    // -------------------------------------------------------------------------
    // STEP 3 — Update video lesson file_paths
    // -------------------------------------------------------------------------
    $videoUpdates = [
        24 => 'videos/arise_drug_abuse.mp4',
        36 => 'videos/arise_healthy_relationships.mp4',
        27 => 'videos/arise_abstinence.mp4',
        38 => 'videos/arise_stds.mp4',
        28 => 'videos/arise_adolescent_growth.mp4',
        39 => 'videos/arise_social_media_srh.mp4',
        40 => 'videos/arise_uti.mp4',
        37 => 'videos/arise_mental_health.mp4',
        41 => 'videos/arise_gambling.mp4',
        43 => 'videos/arise_career_decisions.mp4',
        44 => 'videos/arise_cyber_crimes.mp4',
    ];
    $updated = 0;
